if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch (e) {}
}

if (!body || typeof body !== 'object' || Array.isArray(body)) {
  throw new Error('Invalid JSON payload');
}

const eventName = String(body.event_name || '').trim();
if (!eventName) throw new Error('Missing event_name');
if (!body.tenant_id) throw new Error('Missing tenant_id');

const authEvents = new Set([
  'account_owner_paid_signup_created',
  'account_owner_google_paid_signup_created',
  'team_member_invited',
  'customer_portal_invited',
  'setup_link_expiring',
  'setup_link_expired',
  'payment_successful',
]);

const automationEvents = new Set([
  'lead_captured',
  'lead_stage_changed',
  'payment_failed',
  'payment_recovered',
  'funnel_opt_in_submitted',
  'funnel_checkout_started',
  'funnel_payment_paid',
  'funnel_checkout_abandoned',
  'funnel_order_delivery_updated',
  'funnel_upsell_accepted',
  'funnel_upsell_declined',
  'funnel_downsell_accepted',
  'funnel_downsell_declined',
]);

const financeEvents = new Set([
  'receipt_uploaded',
  'receipt_auto_approved',
  'receipt_approved',
  'receipt_rejected',
  'commission_created',
  'commission_payable',
  'subscription_paid',
  'subscription_overdue',
  'subscription_recovered',
  'subscription_deadline_reminder_7_days_owner',
  'subscription_deadline_reminder_3_days_owner',
  'payout_account_pending_review',
  'payout_account_approved',
  'payout_account_rejected',
  'settlement_payout_recorded',
]);

let workflowRoute = 'finance';
if (authEvents.has(eventName)) {
  workflowRoute = 'auth';
} else if (automationEvents.has(eventName)) {
  workflowRoute = 'automation';
} else if (financeEvents.has(eventName)) {
  workflowRoute = 'finance';
}

const fallbackEventId = `n8n:${eventName}:${Date.now()}`;
const eventId = String(body.event_id || fallbackEventId).trim() || fallbackEventId;
const idempotencyKey = String(body.idempotency_key || `${eventName}:${eventId}`).trim() || `${eventName}:${eventId}`;
const occurredAt = String(body.occurred_at || new Date().toISOString()).trim() || new Date().toISOString();

return {
  json: {
    ...body,
    event_name: eventName,
    event_id: eventId,
    idempotency_key: idempotencyKey,
    occurred_at: occurredAt,
    workflow_route: workflowRoute,
  }
};

